V11A_ASSIGNMENT_TESTS = [('v11a', 'v11a assignment operator OK', '\nmodule V11aAssignOk\nprocedure main()\nis\n    let x: Integer = 1\n    x := x + 1\n    check x = 2\nend main\nend V11aAssignOk\n', True), ('v11a', 'v11a field assignment operator OK', '\nmodule V11aFieldAssignOk\ntype Address is record\n    city_id: Integer\nend record\ntype Customer is record\n    id: Integer\n    address: Address\nend record\nprocedure main()\nis\n    let c: Customer = Customer { id: 1, address: Address { city_id: 42 } }\n    c.address.city_id := 99\n    check c.address.city_id = 99\nend main\nend V11aFieldAssignOk\n', True), ('v11a', 'v11a old plain assignment fails', '\nmodule V11aOldAssignFails\nprocedure main()\nis\n    let x: Integer = 1\n    x = x + 1\nend main\nend V11aOldAssignFails\n', False), ('v11a', 'v11a old field assignment fails', '\nmodule V11aOldFieldAssignFails\ntype Box is record\n    value: Integer\nend record\nprocedure main()\nis\n    let b: Box = Box { value: 1 }\n    b.value = 2\nend main\nend V11aOldFieldAssignFails\n', False), ('v11a', 'v11a equality unchanged OK', '\nmodule V11aEqualityOk\nprocedure main()\nis\n    let x: Integer = 1\n    check x = 1\nend main\nend V11aEqualityOk\n', True)]
